SPARQL.Query:
SELECT ?current ?year WHERE {
  BIND(NOW() AS ?current).
  BIND(YEAR(?current) AS ?year).
  FILTER(xsd:integer(?year) > 20)
}

SELECT ?current ?year WHERE {
  BIND(NOW() AS ?current).
  BIND(YEAR(?current) AS ?year).
}

SELECT ?current WHERE {
  BIND(NOW() AS ?current)
}

